1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  items: Item[];
14	}
15	
16	export interface QuoteResult {
17	  premium: number;
18	}
19	
20	export interface Damage {
21	  itemType: string;
22	  amount: number;
23	}
24	
25	export interface Incident {
26	  cause: string;
27	  damages: Damage[];
28	}
29	
30	export interface ClaimResult {
31	  payout: number;
32	  remainingCap: number;
33	}
34	
35	// Runes and moonstones are "components" — a distinct pricing tier that shares
36	// one base premium (and, later, block/alike rules). Naming the shared value
37	// makes the equality intentional rather than a coincidence two entries happen
38	// to share.
39	const COMPONENT_BASE_PREMIUM = 25;
40	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
41	// A "building block" of exactly this many alike components is offered at a
42	// special block premium instead of the per-component price.
43	const COMPONENT_BLOCK_SIZE = 3;
44	const COMPONENT_BLOCK_PREMIUM = 60;
45	
46	const BASE_PREMIUMS: Record<string, number> = {
47	  sword: 100,
48	  amulet: 60,
49	  staff: 80,
50	  potion: 40,
51	  rune: COMPONENT_BASE_PREMIUM,
52	  moonstone: COMPONENT_BASE_PREMIUM,
53	};
54	const PROCESSING_FEE = 5;
55	
56	// Surcharges are expressed as integer percentages and applied as
57	// `amount * percent / 100`, keeping the maths in integers (avoids float errors
58	// such as `100 * 1.1 === 100.00000000000001`).
59	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
60	const CURSE_SURCHARGE_PERCENT = 50;
61	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
62	const HIGH_ENCHANTMENT_MIN_LEVEL = 5;
63	const LOYALTY_DISCOUNT_PERCENT = 20;
64	const LOYALTY_MIN_YEARS = 2;
65	const FOLLOWUP_CONTRACT_DISCOUNT_PERCENT = 15;
66	const FIRST_CONTRACT_INDEX = 0;
67	const DEDUCTIBLE = 100;
68	const HIGH_ENCHANTMENT_CLAIM_MIN_LEVEL = 8;
69	const HIGH_ENCHANTMENT_REIMBURSEMENT_PERCENT = 50;
70	
71	// Sum a numeric measure over a list. Centralises the
72	// `reduce((total, x) => total + f(x), 0)` shape shared by every per-item /
73	// per-damage total in this module, so each caller states only *what* it sums.
74	const sumBy = <T>(items: T[], measure: (item: T) => number): number =>
75	  items.reduce((total, item) => total + measure(item), 0);
76	
77	const percentOf = (amount: number, percent: number): number =>
78	  (amount * percent) / 100;
79	
80	// A surcharge that applies only when a condition holds, expressed as a
81	// percentage of some base amount (and 0 otherwise).
82	const conditionalPercent = (
83	  applies: boolean,
84	  amount: number,
85	  percent: number,
86	): number => (applies ? percentOf(amount, percent) : 0);
87	
88	// The base premium for a given item type, with unknown types priced at 0.
89	// This is the single point that reads BASE_PREMIUMS, so both per-item and
90	// per-group pricing share one definition of "the base price of a type".
91	const basePremiumForType = (type: string): number => BASE_PREMIUMS[type] ?? 0;
92	
93	// An item's effective enchantment level, with an absent enchantment treated as
94	// 0. Centralising the default keeps "unenchanted counts as level 0" in one
95	// place for every threshold check (quote surcharge at 5, claim 50% at 8).
96	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
97	
98	// A single item's base premium. Block pricing is a group-level concern handled
99	// separately in sumBasePremiums, so a plain per-type lookup suffices here.
100	const itemBasePremium = (item: Item): number => basePremiumForType(item.type);
101	
102	const isKnownItemType = (type: string): boolean => type in BASE_PREMIUMS;
103	
104	// Item-specific surcharges, each a percentage of the item's own base premium:
105	// a curse adds 50%, and a highly-enchanted item (level >= 5) adds 30%. They
106	// stack when both apply.
107	const itemSurcharge = (item: Item): number => {
108	  const base = itemBasePremium(item);
109	  const curse = conditionalPercent(
110	    item.cursed ?? false,
111	    base,
112	    CURSE_SURCHARGE_PERCENT,
113	  );
114	  const highEnchantment = conditionalPercent(
115	    enchantmentLevel(item) >= HIGH_ENCHANTMENT_MIN_LEVEL,
116	    base,
117	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
118	  );
119	  return curse + highEnchantment;
120	};
121	
122	const sumItemSurcharges = (items: Item[]): number =>
123	  sumBy(items, itemSurcharge);
124	
125	const countByType = (items: Item[]): Map<string, number> => {
126	  const counts = new Map<string, number>();
127	  for (const item of items) {
128	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
129	  }
130	  return counts;
131	};
132	
133	const componentGroupPremium = (count: number): number =>
134	  count === COMPONENT_BLOCK_SIZE
135	    ? COMPONENT_BLOCK_PREMIUM
136	    : count * COMPONENT_BASE_PREMIUM;
137	
138	const typeGroupPremium = (type: string, count: number): number =>
139	  COMPONENT_TYPES.has(type)
140	    ? componentGroupPremium(count)
141	    : count * basePremiumForType(type);
142	
143	const sumBasePremiums = (items: Item[]): number =>
144	  sumBy([...countByType(items)], ([type, count]) =>
145	    typeGroupPremium(type, count),
146	  );
147	
148	// Policy-wide modifiers scale with the whole policy's base premium.
149	// First-insurance is a surcharge every new policy pays; the loyalty discount
150	// rewards customers at or past the loyalty threshold.
151	const firstInsuranceSurcharge = (policyBase: number): number =>
152	  percentOf(policyBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
153	
154	const loyaltyDiscount = (customer: Customer, policyBase: number): number =>
155	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS
156	    ? percentOf(policyBase, LOYALTY_DISCOUNT_PERCENT)
157	    : 0;
158	
159	// Every contract after the customer's first quote in the scenario is a
160	// follow-up contract and earns a discount.
161	const followUpDiscount = (quoteIndex: number, policyBase: number): number =>
162	  quoteIndex > FIRST_CONTRACT_INDEX
163	    ? percentOf(policyBase, FOLLOWUP_CONTRACT_DISCOUNT_PERCENT)
164	    : 0;
165	
166	// Net signed adjustment that policy-wide modifiers make to the policy base:
167	// the first-insurance surcharge adds, the loyalty and follow-up discounts
168	// subtract. Grouping them keeps the quote formula at "base + item surcharges
169	// + policy-wide adjustments + fee".
170	const policyAdjustments = (
171	  customer: Customer,
172	  quoteIndex: number,
173	  policyBase: number,
174	): number =>
175	  firstInsuranceSurcharge(policyBase) -
176	  loyaltyDiscount(customer, policyBase) -
177	  followUpDiscount(quoteIndex, policyBase);
178	
179	export const quote = (
180	  customer: Customer,
181	  step: QuoteStep,
182	  quoteIndex: number,
183	): QuoteResult => {
184	  for (const item of step.items) {
185	    if (!isKnownItemType(item.type)) {
186	      throw new Error(`unknown item type: ${item.type}`);
187	    }
188	  }
189	  const policyBase = sumBasePremiums(step.items);
190	  const premium = Math.ceil(
191	    policyBase +
192	      sumItemSurcharges(step.items) +
193	      policyAdjustments(customer, quoteIndex, policyBase) +
194	      PROCESSING_FEE,
195	  );
196	  return { premium };
197	};
198	
199	// Reimbursement for one damage before the deductible. A highly-enchanted item
200	// (level >= 8) is reimbursed at 50% of the damage; otherwise in full.
201	const reimbursement = (item: Item, damage: Damage): number =>
202	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_CLAIM_MIN_LEVEL
203	    ? percentOf(damage.amount, HIGH_ENCHANTMENT_REIMBURSEMENT_PERCENT)
204	    : damage.amount;
205	
206	// Payout for one damage: the reimbursement minus the deductible, never below 0.
207	const damagePayout = (item: Item, damage: Damage): number =>
208	  Math.max(0, reimbursement(item, damage) - DEDUCTIBLE);
209	
210	// Removes and returns the first policy item insuring this damage's type. Each
211	// damage consumes a distinct insured item, so a claim with more damages of a
212	// type than the policy covers leaves a damage unmatched — which is rejected.
213	const takeInsuredItem = (available: Item[], damage: Damage): Item => {
214	  const index = available.findIndex((item) => item.type === damage.itemType);
215	  if (index < 0) {
216	    throw new Error(
217	      `damage references item not covered by policy: ${damage.itemType}`,
218	    );
219	  }
220	  return available.splice(index, 1)[0];
221	};
222	
223	export const claim = (
224	  policyItems: Item[],
225	  incident: Incident,
226	  remainingCap: number,
227	): ClaimResult => {
228	  // Each damage consumes a distinct insured item from `available`, so the loop
229	  // is explicit: takeInsuredItem mutates `available` as it goes, and a plain
230	  // accumulator makes that consume-as-you-go ordering visible (rather than
231	  // hiding the side effect inside a pure-looking sumBy).
232	  const available = [...policyItems];
233	  let requested = 0;
234	  for (const damage of incident.damages) {
235	    requested += damagePayout(takeInsuredItem(available, damage), damage);
236	  }
237	  const payout = Math.floor(Math.min(requested, remainingCap));
238	  return { payout, remainingCap: remainingCap - payout };
239	};
